class Solution {
    public boolean detectCapitalUse(String word) {
        int capitalIndex = 0;
        for (int i = 0; i < word.length(); i++) {
            char c = word.charAt(i);
            if (Character.isUpperCase(c)) {
                capitalIndex = i;
                break;
            }
        }
        return capitalIndex == 0 || capitalIndex == word.length() - 1;
    }
}
